mapper.select:
SELECT aa.*
FROM adoptionapplication aa
         JOIN animal a ON aa.animal_id = a.animal_id
WHERE a.shelter_id = #{shelterId}
ORDER BY aa.applied_at DESC
    LIMIT #{offset}, #{pageSize}

mapper.update:
UPDATE adoptionapplication
SET notes = #{notes}
WHERE application_id = #{applicationId}

UPDATE adoptionapplication
SET status = #{status}
WHERE application_id = #{applicationId}
